   251→func (c *Controller) addCustomResourceDefinition(obj interface{}) {
   252→	castObj := obj.(*apiextensionsv1.CustomResourceDefinition)
   253→	klog.V(4).Infof("Adding customresourcedefinition %s", castObj.Name)
   254→	c.enqueue(castObj)
