   257→func (c *Controller) updateCustomResourceDefinition(oldObj, newObj interface{}) {
   258→	castNewObj := newObj.(*apiextensionsv1.CustomResourceDefinition)
   259→	klog.V(4).Infof("Updating customresourcedefinition %s", castNewObj.Name)
   260→	c.enqueue(castNewObj)
   261→}
   262→
   263→func (c *Controller) deleteCustomResourceDefinition(obj interface{}) {
   264→	castObj, ok := obj.(*apiextensionsv1.CustomResourceDefinition)
   265→	if !ok {
   266→		tombstone, ok := obj.(cache.DeletedFinalStateUnknown)
   267→		if !ok {
   268→			klog.Errorf("Couldn't get object from tombstone %#v", obj)
   269→			return
   270→		}
   271→		castObj, ok = tombstone.Obj.(*apiextensionsv1.CustomResourceDefinition)
   272→		if !ok {
   273→			klog.Errorf("Tombstone contained object that is not expected %#v", obj)
   274→			return
   275→		}
   276→	}
   277→	klog.V(4).Infof("Deleting customresourcedefinition %q", castObj.Name)
   278→	c.enqueue(castObj)
   279→}
